local Instance =
	setmetatable(
		{ClearChildrenOfClass = function(where, class, recursive)
		local children = (recursive and where:GetDescendants() or where:GetChildren())
		for _, v in next, children do
			if (v:IsA(class)) then
				v:destroy()
			end
		end
	end},
		{__index = Instance}
	)

