CreatingLmfao = function(obj)
	local inst = Instance.new(obj)
	return function(props)
		for prop, valu in next, props do
			inst[prop] = valu
		end
		return inst
	end
end

NotEchoLmfao = function(id, par, vol, pit, timepos, delays, echodelay, fedb, dryl)
	local Sas =
		CreatingLmfao("Sound") {
			Volume = vol,
			Name = "EffectSoundo",
			Pitch = pit or 1,
			SoundId = id,
			TimePosition = timepos,
			Parent = par or workspace
		}
	local E =
		CreatingLmfao("EchoSoundEffect") {
			Delay = echodelay,
			Name = "NotEchoLmfao",
			Feedback = fedb,
			DryLevel = dryl,
			Parent = Sas
		}
	wait()
	Sas:play()
	game:GetService("Debris"):AddItem(Sas, delays)
end
function newbosschatfunc(text, color1, delay)
	for _, v in next, game:service "Players":players() do
		coroutine.wrap(
			function()
				if (FXFolder:FindFirstChild "BossChat" and v.Character) then
					local cha = FXFolder.BossChat:Clone()
					cha.Color1.Value = Color3.new(1, 1, 1)
					cha.Color2.Value = color1
					cha.Text.Value = text
					cha.Ghghghghgh.Value = delay
					cha.Mode.Value = ModeOfGlitch
					cha.ModeName.Value = modet.Text
					cha.Music.Value = kan
					cha.Parent = v.Character
					wait()
					cha.Disabled = false
					game:service "Debris":AddItem(cha, (delay / 60) * 4)
				end
			end
		)()
	end
end
