CFuncs = {
	["Part"] = {
		Create = function(Parent, Material, Reflectance, Transparency, BColor, Name, Size)
			local Part =
				Create("Part") {
					Parent = Parent,
					Reflectance = Reflectance,
					Transparency = Transparency,
					CanCollide = false,
					Locked = true,
					BrickColor = BrickColor.new(tostring(BColor)),
					Name = Name,
					Size = Size,
					Material = Material
				}
			RemoveOutlines(Part)
			return Part
		end
	},
	["Mesh"] = {
		Create = function(Mesh, Part, MeshType, MeshId, OffSet, Scale)
			local Msh =
				Create(Mesh) {
					Parent = Part,
					Offset = OffSet,
					Scale = Scale
				}
			if Mesh == "SpecialMesh" then
				Msh.MeshType = MeshType
				Msh.MeshId = MeshId
			end
			return Msh
		end
	},
	["Mesh"] = {
		Create = function(Mesh, Part, MeshType, MeshId, OffSet, Scale)
			local Msh =
				Create(Mesh) {
					Parent = Part,
					Offset = OffSet,
					Scale = Scale
				}
			if Mesh == "SpecialMesh" then
				Msh.MeshType = MeshType
				Msh.MeshId = MeshId
			end
			return Msh
		end
	},
	["Weld"] = {
		Create = function(Parent, Part0, Part1, C0, C1)
			local Weld =
				Create("Weld") {
					Parent = Parent,
					Part0 = Part0,
					Part1 = Part1,
					C0 = C0,
					C1 = C1
				}
			return Weld
		end
	},
	["Sound"] = {
		Create = function(id, par, vol, pit)
			coroutine.resume(
				coroutine.create(
					function()
						local S =
							Create("Sound") {
								Volume = vol,
								Name = "EffectSoundo",
								Pitch = pit or 1,
								SoundId = id,
								Parent = par or workspace
							}
						wait()
						S:play()
						game:GetService("Debris"):AddItem(S, 10)
					end
				)
			)
		end
	},
	["TimeSound"] = {
		Create = function(id, par, vol, pit, timepos)
			coroutine.resume(
				coroutine.create(
					function()
						local S =
							Create("Sound") {
								Volume = vol,
								Name = "EffectSoundo",
								Pitch = pit or 1,
								SoundId = id,
								TimePosition = timepos,
								Parent = par or workspace
							}
						wait()
						S:play()
						game:GetService("Debris"):AddItem(S, 10)
					end
				)
			)
		end
	},
	["EchoSound"] = {
		Create = function(id, par, vol, pit, timepos, delays, echodelay, fedb, dryl)
			coroutine.resume(
				coroutine.create(
					function()
						local Sas =
							Create("Sound") {
								Volume = vol,
								Name = "EffectSoundo",
								Pitch = pit or 1,
								SoundId = id,
								TimePosition = timepos,
								Parent = par or workspace
							}
						local E =
							Create("EchoSoundEffect") {
								Delay = echodelay,
								Name = "Echo",
								Feedback = fedb,
								DryLevel = dryl,
								Parent = Sas
							}
						wait()
						Sas:play()
						game:GetService("Debris"):AddItem(Sas, delays)
					end
				)
			)
		end
	},
	["LongSound"] = {
		Create = function(id, par, vol, pit)
			coroutine.resume(
				coroutine.create(
					function()
						local S =
							Create("Sound") {
								Volume = vol,
								Pitch = pit or 1,
								SoundId = id,
								Parent = par or workspace
							}
						wait()
						S:play()
						game:GetService("Debris"):AddItem(S, 60)
					end
				)
			)
		end
	},
	["ParticleEmitter"] = {
		Create = function(
			Parent,
			Color1,
			Color2,
			LightEmission,
			Size,
			Texture,
			Transparency,
			ZOffset,
			Accel,
			Drag,
			LockedToPart,
			VelocityInheritance,
			EmissionDirection,
			Enabled,
			LifeTime,
			Rate,
			Rotation,
			RotSpeed,
			Speed,
			VelocitySpread)
			local fp =
				Create("ParticleEmitter") {
					Parent = Parent,
					Color = ColorSequence.new(Color1, Color2),
					LightEmission = LightEmission,
					Size = Size,
					Texture = Texture,
					Transparency = Transparency,
					ZOffset = ZOffset,
					Acceleration = Accel,
					Drag = Drag,
					LockedToPart = LockedToPart,
					VelocityInheritance = VelocityInheritance,
					EmissionDirection = EmissionDirection,
					Enabled = Enabled,
					Lifetime = LifeTime,
					Rate = Rate,
					Rotation = Rotation,
					RotSpeed = RotSpeed,
					Speed = Speed,
					VelocitySpread = VelocitySpread
				}
			return fp
		end
	},
	CreateTemplate = {}
}

New = function(Object, Parent, Name, Data)
	local Object = Instance.new(Object)
	for Index, Value in pairs(Data or {}) do
		Object[Index] = Value
	end
	Object.Parent = Parent
	Object.Name = Name
	return Object
end
