function waveEff(bonuspeed, type, typeoftrans, pos, scale, value, value2, color)
	local type = type
	local rng = Instance.new("Part", char)
	rng.Anchored = true
	rng.BrickColor = color
	rng.CanCollide = false
	rng.FormFactor = 3
	rng.Name = "Ring"
	rng.Material = "Neon"
	rng.Size = Vector3.new(1, 1, 1)
	rng.Transparency = 0
	if typeoftrans == "In" then
		rng.Transparency = 1
	end
	rng.TopSurface = 0
	rng.BottomSurface = 0
	rng.CFrame = pos
	local rngm = Instance.new("SpecialMesh", rng)
	rngm.MeshType = "FileMesh"
	rngm.MeshId = "rbxassetid://20329976"
	rngm.Scale = scale
	local scaler2 = 1
	local scaler2b = 1
	if type == "Add" then
		scaler2 = 1 * value
		scaler2b = 1 * value2
	elseif type == "Divide" then
		scaler2 = 1 / value
		scaler2b = 1 / value2
	end
	local randomrot = math.random(1, 2)
	coroutine.resume(
		coroutine.create(
			function()
				for i = 0, 10 / bonuspeed, 0.1 do
					swait()
					if type == "Add" then
						scaler2 = scaler2 - 0.01 * value / bonuspeed
						scaler2b = scaler2b - 0.01 * value / bonuspeed
					elseif type == "Divide" then
						scaler2 = scaler2 - 0.01 / value * bonuspeed
						scaler2b = scaler2b - 0.01 / value * bonuspeed
					end
					if randomrot == 1 then
						rng.CFrame = rng.CFrame * CFrame.Angles(0, math.rad(5 * bonuspeed / 2), 0)
					elseif randomrot == 2 then
						rng.CFrame = rng.CFrame * CFrame.Angles(0, math.rad(-5 * bonuspeed / 2), 0)
					end
					if typeoftrans == "Out" then
						rng.Transparency = rng.Transparency + 0.01 * bonuspeed
					elseif typeoftrans == "In" then
						rng.Transparency = rng.Transparency - 0.01 * bonuspeed
					end
					rngm.Scale =
						rngm.Scale + Vector3.new(scaler2 * bonuspeed, scaler2b * bonuspeed, scaler2 * bonuspeed)
				end
				rng:Destroy()
			end
		)
	)
end

function StravEffect(brickcolor, cframe, x, y, z, x1, y1, z1, delay)
	local prt = part(3, workspace, 0, 0, brickcolor, "Effect", vt(0.5, 0.5, 0.5))
	prt.Anchored = true
	prt.CFrame = cframe * cf(x, y, z)
	msh = mesh("SpecialMesh", prt, "FileMesh", "rbxassetid://168892363", vt(0, 0, 0), vt(x1, y1, z1))
	game:GetService("Debris"):AddItem(prt, 5)
	coroutine.resume(
		coroutine.create(
			function(Part, Mesh, ex, why, zee)
				local num = math.random()
				local num2 = math.random(-3, 2) + math.random()
				local numm = 0
				for i = 0, 1, delay * 2 do
					swait()
					Part.CFrame = cframe * euler(0, numm * num * 10, 0) * cf(ex, why, zee) * cf(-i * 10, num2, 0)
					Part.Transparency = i
					numm = numm + 0.01
				end
				Part.Parent = nil
				Mesh.Parent = nil
			end
		),
		prt,
		msh,
		x,
		y,
		z
	)
end

function dmgstart(dmg, what)
	hitcon =
		what.Touched:connect(
			function(hit)
			local hum = hit.Parent:FindFirstChild("Humanoid")
			if hum and not hum:IsDescendantOf(Character) then
				hum:TakeDamage(dmg)
			end
		end
		)
end

function dmgstop()
	hitcon:disconnect()
end

function Cloak()
	Face.Parent = nil
	cloaked = true
	for _, v in pairs(Torso.Parent:children()) do
		if v.className == "Part" and v.Name ~= "HumanoidRootPart" then
			coroutine.resume(
				coroutine.create(
					function()
						for i = 0, 1, 0.2 do
							wait()
							v.Transparency = i
						end
						v.Transparency = 1
					end
				)
			)
		end
		if v.className == "Hat" then
			hatp = v.Handle
			coroutine.resume(
				coroutine.create(
					function(derp)
						for i = 0, 1, 0.2 do
							wait()
							derp.Transparency = i
						end
						derp.Transparency = 1
					end
				),
				hatp
			)
		end
	end
	for _, v in pairs(m:children()) do
		if v.className == "Part" then
			coroutine.resume(
				coroutine.create(
					function()
						for i = 0, 1, 0.2 do
							wait()
							v.Transparency = i
						end
						v.Transparency = 1
					end
				)
			)
		end
	end
end

function UnCloak()
	so("http://roblox.com/asset/?id=2767090", Torso, 1, 1.1)
	Face.Parent = Head
	cloaked = false
	for _, v in pairs(Torso.Parent:children()) do
		if v.className == "Part" and v.Name ~= "HumanoidRootPart" then
			coroutine.resume(
				coroutine.create(
					function()
						for i = 0, 1, 0.1 do
							wait()
							v.Transparency = v.Transparency - 0.1
						end
						v.Transparency = 0
					end
				)
			)
		end
		if v.className == "Hat" then
			hatp = v.Handle
			coroutine.resume(
				coroutine.create(
					function(derp)
						for i = 0, 1, 0.1 do
							wait()
							derp.Transparency = derp.Transparency - 0.1
						end
						derp.Transparency = 0
					end
				),
				hatp
			)
		end
	end
	for _, v in pairs(m:children()) do
		if v.className == "Part" and v.Name ~= "hitbox" and v.Name ~= "tip" then
			coroutine.resume(
				coroutine.create(
					function()
						for i = 0, 1, 0.1 do
							wait()
							v.Transparency = v.Transparency - 0.1
						end
						v.Transparency = 0
					end
				)
			)
			v.Transparency = 0
		end
	end
end

