	rng.TopSurface = 0
	rng.BottomSurface = 0
	rng.CFrame = pos
	local rngm = Instance.new("SpecialMesh", rng)
	rngm.MeshType = "Brick"
	rngm.Scale = scale
	local scaler2 = 1
	local scaler2b = 1
	local scaler2c = 1
	if type == "Add" then
		scaler2 = 1 * value
		scaler2b = 1 * value2
		scaler2c = 1 * value3
	elseif type == "Divide" then
		scaler2 = 1 / value
		scaler2b = 1 / value2
		scaler2c = 1 / value3
	end
	coroutine.resume(
		coroutine.create(
			function()
				for i = 0, 10 / bonuspeed, 0.1 do
					swait()
					if type == "Add" then
						scaler2 = scaler2 - 0.01 * value / bonuspeed
						scaler2b = scaler2b - 0.01 * value / bonuspeed
						scaler2c = scaler2c - 0.01 * value / bonuspeed
					elseif type == "Divide" then
						scaler2 = scaler2 - 0.01 / value * bonuspeed
						scaler2b = scaler2b - 0.01 / value * bonuspeed
						scaler2c = scaler2c - 0.01 / value * bonuspeed
					end
					rng.CFrame =
						rng.CFrame *
						CFrame.Angles(
							math.rad(math.random(-360, 360)),
							math.rad(math.random(-360, 360)),
							math.rad(math.random(-360, 360))
						)
					rng.Transparency = rng.Transparency + 0.01 * bonuspeed
					rngm.Scale =
						rngm.Scale + Vector3.new(scaler2 * bonuspeed, scaler2b * bonuspeed, scaler2c * bonuspeed)
				end
				rng:Destroy()
			end
		)
	)
end

