val.Name = "IsHit"]] local ds =
			coroutine.wrap(
				function()
				dude:WaitForChild("Head"):BreakJoints()
				for i, v in pairs(dude:GetChildren()) do
					if v:IsA("Part") or v:IsA("MeshPart") then
						v.Name = "DEMINISHED"
					end
				end
				wait(0.5)
				targetted = nil
				CFuncs["Sound"].Create("rbxassetid://62339698", char, 0.75, 0.285)
