function magnishake(part,magni,power,length) --disabled for a bit
	magni = magni * mult
	power = power
	for i,v in pairs(game:GetService("Players"):GetChildren()) do
		local var = script.Shaker:Clone()
		var.Parent = v.Character
		local pw = var.Shakeval
		local lgth = var.MultLength
		local mult = (magni/((v.Character.PrimaryPart.Position - part.Position).magnitude))
		if mult > 1 then
			mult = 1
		end
		pw.Value = power * mult
		lgth.Value = length * mult
		var.Disabled = false
		game:GetService("Debris"):AddItem(var, 20)
	end
end
function CamShakeAll(times,intense,origin)
	for _,v in next, Plrs:players() do
		CamShake(v:FindFirstChildOfClass'PlayerGui' or v:FindFirstChildOfClass'Backpack' or v.Character,times,intense,origin)
	end
end
