	obj1.Color = BrickColor.new("Pink").Color
	local obj2 = script.spball:Clone()
	obj2.Parent = char
	obj2.Transparency = 1
	obj2.Size = vt(1,1,1)
	obj2.Color = MAINRUINCOLOR.Color
	local cfor = CreateParta(char,1,1,"Neon",MAINRUINCOLOR)
