		RootJoint.C0 =
			clerp(
				RootJoint.C0,
				RootCF * cf(0 - 0.25 * math.cos(sine / 50), 0 + 0.25 * math.cos(sine / 43), 0.1 + 0.6 * math.cos(sine / 32)) *
