	trl.LightEmission = 1
	trl.FaceCamera = true
	trl.Transparency = NumberSequence.new({NumberSequenceKeypoint.new(0, 0), NumberSequenceKeypoint.new(1, 1)})
	trl.Color = ColorSequence.new(dis.Color)
	trl.Lifetime = 3
